package apikeys

import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type sqrcQueries interface {
	InsertApiKey(ctx context.Context, arg db.InsertApiKeyParams) error
	CountApiKeyByUserID(ctx context.Context, userid pgtype.UUID) (int64, error)
}

type ApiKeySqrcRepository struct {
	queries sqrcQueries
}

func NewApiKeySqrcRepository(sqrc sqrcQueries) ApiKeySqrcRepository {
	return ApiKeySqrcRepository{queries: sqrc}
}

func (repo ApiKeySqrcRepository) count(ctx context.Context, userId string) int {
	var userID pgtype.UUID
	if err := userID.Scan(userId); err != nil {
		return 0
	}
	count, err := repo.queries.CountApiKeyByUserID(ctx, userID)
	if err != nil {
		return 0
	}
	return int(count)
}

func (repo ApiKeySqrcRepository) save(ctx context.Context, apiKey hashedApiKey) error {
	var apikeyID pgtype.UUID
	var userID pgtype.UUID

	if err := apikeyID.Scan(apiKey.apiKeyID); err != nil {
		return err
	}
	if err := userID.Scan(apiKey.userID); err != nil {
		return err
	}

	var expiredAt pgtype.Timestamptz
	if apiKey.expiredAt == nil {
		expiredAt = pgtype.Timestamptz{
			InfinityModifier: pgtype.Infinity,
			Valid:            true,
		}
	} else {
		expiredAt = pgtype.Timestamptz{
			Time:  *apiKey.expiredAt,
			Valid: true,
		}
	}

	return repo.queries.InsertApiKey(ctx, db.InsertApiKeyParams{
		ApikeyID:       apikeyID,
		KeyHash:        apiKey.hashedApiKey,
		UserID:         userID,
		KeyPlainSuffix: apiKey.plainApiKeySuffix,
		ExpiredAt:      expiredAt,
	})
}

package apikeys

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"errors"
	"fmt"
	"time"

	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
)

type hashedApiKey struct {
	apiKeyID          string
	hashedApiKey      string
	plainApiKeySuffix string
	userID            string
	expiredAt         *time.Time
}

type NewHashedApiKeyParams struct {
	UserID    string
	ExpiredAt *time.Time
}

var ErrApiKeyCountExceedsLimit = errors.New("API key count exceeds the limit")

const apiKeyMaxCount = 5

func NewHashedApiKey(params NewHashedApiKeyParams) (hashedApiKey, string) {
	plainKey := generatePlainApiKey()
	key := hashedApiKey{
		apiKeyID:          uuid.MustNewUuidString(),
		userID:            params.UserID,
		hashedApiKey:      getHash(plainKey),
		plainApiKeySuffix: plainKey[len(plainKey)-4:],
		expiredAt:         params.ExpiredAt,
	}

	return key, plainKey
}

// SHA256 を使用しているが、API キーは crypto/rand で生成した 32 バイト（256 ビット）の
// 高エントロピーなトークンであるため、高速なハッシュでも総当たり攻撃は現実的に不可能。
// また、リクエストごとに検証が発生するため bcrypt などの低速アルゴリズムは不適切。
// nolint:gosec
func getHash(plain string) string {
	hash := sha256.Sum256([]byte(plain))
	return hex.EncodeToString(hash[:])
}

func generatePlainApiKey() string {
	b := make([]byte, 32)

	if _, err := rand.Read(b); err != nil {
		panic(err)
	}

	return fmt.Sprintf("jukubox_%s", base64.RawURLEncoding.EncodeToString(b))
}

package uuid

import (
	"regexp"
	"strings"

	"github.com/google/uuid"
)

var uuidRegex = regexp.MustCompile(`^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$`)

func IsValidUuid(s string) bool {
	return uuidRegex.MatchString(strings.ToLower(s))
}

func MustNewUuidString() string {
	id, err := uuid.NewV7()
	if err != nil {
		// crypto/rand の読み取り失敗したケースなど通常環境では基本的に発生しないため panic で終了する
		panic(err)
	}

	return id.String()
}

package apikeys_test

import (
	"context"
	"encoding/json"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
	"github.com/harusame0616/ijuku/apps/api/routes/users/settings/apikeys"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestGenerateApiKeyHandlerMedium(t *testing.T) {
	ctx := context.Background()
	pool, err := pgxpool.New(ctx, "postgresql://postgres:password@localhost:5432/postgres")
	if err != nil {
		t.Fatalf("DBへの接続に失敗しました: %v", err)
	}
	defer pool.Close()

	q := db.New(pool)
	handler := apikeys.NewGenerateApiKeyHandler(apikeys.NewGenerateApiKeyUsecase(apikeys.NewApiKeySqrcRepository(q)))

	t.Run("userId が未定義の場合 Internal Server Error を返す", (func(t *testing.T) {
		r := httptest.NewRequest("POST", "/v1/users/{userID}/apikeys", strings.NewReader("{}"))
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "SERVER_INTERNAL_ERROR",
			"message":   "An unexpected error occurred. Please try again later.",
		}, responseBody)
	}))

	t.Run("userId が非 UUID の場合 Input Validation Error を返す", (func(t *testing.T) {
		r := httptest.NewRequest("POST", "/v1/users/{userID}/apikeys", strings.NewReader("{}"))
		r.SetPathValue("userID", "invalid-uuid")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "User ID must be valid UUID",
		}, responseBody)
	}))

	t.Run("expiredAt のフォーマットが ISO 8601 フォーマットではない場合 Input Validation Error を返す", (func(t *testing.T) {
		r := httptest.NewRequest("POST", "/v1/users/{userID}/apikeys", strings.NewReader(`{"expiredAt": "invalid format"}`))
		r.SetPathValue("userID", "BD30D30D-01A0-4E43-A00D-1E6EB88A1D54")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "expiredAt must be ISO 8601 format",
		}, responseBody)
	}))

	t.Run("Body のフォーマットが json フォーマットではない場合 Input Validation Error を返す", (func(t *testing.T) {
		r := httptest.NewRequest("POST", "/v1/users/{userID}/apikeys", strings.NewReader(`invalid json`))
		r.SetPathValue("userID", "BD30D30D-01A0-4E43-A00D-1E6EB88A1D54")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "Body must be valid JSON",
		}, responseBody)
	}))

	t.Run("API KEY が上限を超えている場合 Apikey Quota Exceeds Limit Error を返す", (func(t *testing.T) {
		userID := uuid.MustNewUuidString()
		if _, err := pool.Exec(ctx, `INSERT INTO users (user_id, nickname) VALUES ($1, 'テストユーザー')`, userID); err != nil {
			require.Fail(t, "データの投入エラー: テストユーザー", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 1", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 2", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 3", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 4", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 5", err)
		}

		r := httptest.NewRequest("POST", "/v1/users/{userID}/apikeys", strings.NewReader("{}"))
		r.SetPathValue("userID", userID)
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "APIKEY_QUOTA_EXCEEDS_LIMIT",
			"message":   "Api key quota exceeds limit. Api key quota limit is 5",
		}, responseBody)

		pool.Exec(ctx, "DELETE FROM apikeys WHERE user_id = $1", userID)
		pool.Exec(ctx, "DELETE FROM users WHERE user_id = $1", userID)
	}))

	t.Run("API KEY が上限を登録できる", (func(t *testing.T) {
		userID := uuid.MustNewUuidString()
		if _, err := pool.Exec(ctx, `INSERT INTO users (user_id, nickname) VALUES ($1, 'テストユーザー')`, userID); err != nil {
			require.Fail(t, "データの投入エラー: テストユーザー", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
			require.Fail(t, "データの投入エラー: API 1", err)
		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuid.MustNewUuidString(), userID, uuid.MustNewUuidString()); err != nil {
